const isKnownItemType = (item: Item): boolean => item.type in BASE_PREMIUMS;

const assertKnownItemTypes = (items: Item[]): void => {
  for (const item of items) {
    if (!isKnownItemType(item)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
};
